// Keep the latest reading in flow context so the page node can read it.
// Stamped with an ARRIVAL TIME, because a node that stopped reporting looks
// identical to one that never started unless you track when you last heard it.
const p = msg.payload;
flow.set("water", Object.assign({}, p, { at: Date.now() }));

// ok:false means the ESP is alive and the probe is not. Show it as a fault
// rather than dropping it — that's a different repair job from silence.
if (p.ok === false) {
    node.status({ fill: "red", shape: "ring", text: "probe fault: " + p.error });
    return null;
}

let text = p.depth_mm + " mm";
if (p.percent !== undefined) text += "  (" + p.percent + "%)";
node.status({ fill: "green", shape: "dot", text: text });

return { payload: p.depth_mm, topic: p.node };

const p = msg.payload;
flow.set("soil", Object.assign({}, p, { at: Date.now() }));

if (p.ok === false) {
    node.status({ fill: "red", shape: "ring", text: "probe fault: " + p.error });
    return null;
}

node.status({
    fill: "green", shape: "dot",
    text: p.moisture_pct + " %  |  " + p.temp_c + " C  |  EC " + p.ec
});

return { payload: p.moisture_pct, topic: p.node };

// A live page from core nodes only — no node-red-dashboard install.
// Every extra install step is a place a build dies on someone else's phone.
const now = Date.now();
const STALE_MS = 90000;   // ~1.5x the firmware's default 60s report interval

function card(title, r, body) {
    if (!r) {
        return '<div class="c wait"><h2>' + title + '</h2>'
             + '<p class="big">--</p><p class="s">waiting for first reading</p></div>';
    }
    const secs = Math.round((now - r.at) / 1000);
    if (r.ok === false) {
        return '<div class="c bad"><h2>' + title + '</h2>'
             + '<p class="big">FAULT</p><p class="s">' + r.error + '</p>'
             + '<p class="s">' + secs + 's ago</p></div>';
    }
    const stale = (now - r.at) > STALE_MS;
    return '<div class="c ' + (stale ? 'stale' : 'good') + '"><h2>' + title + '</h2>'
         + body(r)
         + '<p class="s">' + secs + 's ago' + (stale ? ' &mdash; STALE' : '') + '</p></div>';
}

const waterCard = card('Water tank', flow.get('water'), function (r) {
    let s = '<p class="big">' + r.depth_mm + '<span>mm</span></p>';
    if (r.percent !== undefined) s += '<p class="s">' + r.percent + '% full</p>';
    if (r.raw !== undefined) s += '<p class="s">raw ' + r.raw + '</p>';
    return s;
});

const soilCard = card('Soil', flow.get('soil'), function (r) {
    return '<p class="big">' + r.moisture_pct + '<span>%</span></p>'
         + '<p class="s">' + r.temp_c + ' &deg;C &nbsp;|&nbsp; EC ' + r.ec + ' &micro;S/cm</p>';
});

msg.headers = { 'content-type': 'text/html; charset=utf-8' };
msg.payload =
'<!DOCTYPE html><html><head><meta charset="utf-8">'
+ '<meta name="viewport" content="width=device-width,initial-scale=1">'
+ '<meta http-equiv="refresh" content="2">'
+ '<title>Farmers IoT</title><style>'
+ 'body{margin:0;padding:16px;background:#12161c;color:#e8eef6;'
+ 'font-family:system-ui,-apple-system,sans-serif}'
+ 'h1{font-size:1.1rem;font-weight:600;color:#8fa3bb;margin:0 0 16px}'
+ '.g{display:grid;gap:12px;grid-template-columns:repeat(auto-fit,minmax(240px,1fr))}'
+ '.c{background:#1b212b;border-radius:12px;padding:18px;border-left:5px solid #3a4553}'
+ '.c.good{border-left-color:#3fb950}.c.stale{border-left-color:#d29922}'
+ '.c.bad{border-left-color:#f85149}.c.wait{border-left-color:#3a4553}'
+ 'h2{font-size:.8rem;text-transform:uppercase;letter-spacing:.08em;'
+ 'color:#8fa3bb;margin:0 0 10px;font-weight:600}'
+ '.big{font-size:2.6rem;font-weight:700;margin:0;line-height:1.1}'
+ '.big span{font-size:1rem;font-weight:500;color:#8fa3bb;margin-left:6px}'
+ '.s{margin:6px 0 0;font-size:.85rem;color:#8fa3bb}'
+ '.c.bad .big{color:#f85149;font-size:1.8rem}'
+ '</style></head><body><h1>Farmers IoT Toolkit</h1><div class="g">'
+ waterCard + soilCard
+ '</div></body></html>';

return msg;
